const Sponsors: React.FC = () => {

  // Configuração de estilos baseada no Tier
  const getTierStyles = (tier: SponsorTier) => {
    switch (tier) {
      case 'Master':
        return {
          // 1 por linha no mobile, ~2 por linha no desktop (45% cada deixa espaço para o gap)
          widthClass: "w-full md:w-[45%]", 
          heightClass: "h-40 md:h-48",
          imgClass: "max-h-20 md:max-h-24"
        };
      case 'Gold':
        return {
          // 1 mobile, ~2 tablet (45%), ~3 desktop (30%)
          widthClass: "w-full sm:w-[45%] lg:w-[30%]",
          heightClass: "h-32 md:h-40",
          imgClass: "max-h-14 md:max-h-16"
        };
      case 'Support':
        return {
          // ~2 mobile (45%), ~4 desktop (22%)
          widthClass: "w-[45%] md:w-[22%]",
          heightClass: "h-24 md:h-32",
          imgClass: "max-h-10 md:max-h-12"
        };
    }
  };

  const renderTier = (tier: SponsorTier, title: string, description: string) => {
    const tierSponsors = sponsors.filter(s => s.tier === tier);

    if (tierSponsors.length === 0) return null;

    const styles = getTierStyles(tier);
    const isMaster = tier === 'Master';

    return (
      <div className="mb-16 last:mb-0">
        <div className="text-center mb-8">
          <span className={`inline-block px-4 py-1.5 rounded-full text-xs font-bold tracking-widest uppercase mb-2 ${isMaster ? 'bg-un-dark text-white shadow-lg' : 'bg-slate-200 text-slate-600'}`}>
            {title}
          </span>
          {isMaster && <p className="text-slate-500 text-sm mt-2">{description}</p>}
        </div>

        {/* 
            FLEXBOX CONTAINER 
            justify-center: Garante que se houver um número ímpar de itens (ex: 3 itens em uma linha de 4),
            os itens restantes ficarão centralizados na linha de baixo, e não alinhados à esquerda.
            gap-6/gap-8: Espaçamento consistente.
        */}
        <div className="flex flex-wrap justify-center gap-6 md:gap-8 max-w-7xl mx-auto px-2">
          {tierSponsors.map((sponsor, idx) => (
            <motion.div
              key={`${tier}-${idx}`}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true, margin: "-50px" }}
              transition={{ duration: 0.5, delay: idx * 0.1 }}
              whileHover={{ y: -5 }}
              className={`
                bg-white rounded-xl shadow-sm border border-slate-100 
                flex items-center justify-center p-6 relative overflow-hidden group
                transition-all duration-300 hover:shadow-xl hover:border-un-blue/30 
                ${styles.widthClass} ${styles.heightClass}
              `}
            >
              {/* Efeito de brilho no hover */}
              <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-transparent to-un-blue/5 opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

              <img 
                src={sponsor.url} 
                alt={`Logo ${sponsor.name}`}
                className={`${styles.imgClass} w-auto object-contain grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-500 transform group-hover:scale-105`}
                loading="lazy"
              />
            </motion.div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <section className="py-24 bg-slate-50 relative overflow-hidden">
      {/* Background patterns */}
      <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-un-dark via-un-blue to-un-accent"></div>
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#1E4F84 1px, transparent 1px)', backgroundSize: '30px 30px' }}></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">

        {/* Cabeçalho da Seção */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <div className="inline-flex items-center justify-center p-3 bg-white rounded-full shadow-sm mb-4">
            <Handshake className="w-6 h-6 text-un-blue" />
          </div>
          <h2 className="text-un-blue font-bold tracking-wide uppercase text-sm mb-2">Nossos Parceiros</h2>
          <h3 className="text-3xl md:text-4xl font-serif font-bold text-slate-900 mb-8">Quem torna o sonho possível</h3>

          <p className="max-w-4xl mx-auto text-slate-600 text-lg leading-relaxed text-justify md:text-center mb-10">
            A <span className="text-un-blue font-bold">SINU XX</span> é mais do que uma simulação acadêmica. Trata-se de um projeto educacional que forma jovens críticos, engajados e preparados para debater os principais desafios do cenário global. Ao apoiar a SINU, sua instituição investe diretamente em educação de qualidade, protagonismo juvenil e impacto social, além de fortalecer sua marca junto a um público jovem, qualificado e altamente engajado.
          </p>
        </motion.div>

        {/* Listagem de Patrocinadores */}
        <div className="space-y-8">
          {renderTier('Master', 'Patrocínio Master', 'Apoio fundamental para a estrutura do evento')}
          {renderTier('Gold', 'Patrocínio Ouro', '')}
          {renderTier('Support', 'Apoio Institucional', '')}
        </div>
      </div>
    </section>
  );
};

